import React, { useState } from 'react';
import type { AppState, ShopItem, CustomTheme } from '../types';
import { ShoppingBagIcon, SparklesIcon, LockClosedIcon, CheckCircleIcon, PaintBrushIcon, UserIcon, StarIconFilled, HeartIcon, ShieldCheckIcon, Squares2x2Icon, LightbulbIcon, ArrowPathIcon, PhotoIcon } from './Icons';
