    { id: 'theme_berry', name: 'Beri (Berry)', description: 'Sentuhan pink & ungu yang playful.', price: 1200, type: 'theme', value: 'theme_berry', icon: 'PaintBrushIcon' },

    // --- FEMININE THEMES ---
    { id: 'theme_rose', name: 'Rose Gold', description: 'Sentuhan pink mewah nan elegan.', price: 1500, type: 'theme', value: 'theme_rose', icon: 'HeartIcon' },
    { id: 'theme_lavender', name: 'Lavender Soft', description: 'Ungu lembut yang menenangkan jiwa.', price: 1500, type: 'theme', value: 'theme_lavender', icon: 'SparklesIcon' },
