    // --- MASCULINE THEMES ---
    { id: 'theme_midnight', name: 'Midnight Pro', description: 'Mode gelap biru deep untuk fokus tinggi.', price: 1800, type: 'theme', value: 'theme_midnight', icon: 'LockClosedIcon' },
    { id: 'theme_forest', name: 'Ranger Green', description: 'Nuansa hutan taktis yang maskulin.', price: 1800, type: 'theme', value: 'theme_forest', icon: 'ShieldCheckIcon' },
    { id: 'theme_slate', name: 'Slate Monochrome', description: 'Hitam putih minimalis yang futuristik.', price: 1800, type: 'theme', value: 'theme_slate', icon: 'Squares2x2Icon' },

