    { id: 'frame_diamond', name: 'Diamond Aura', description: 'Bingkai neon futuristik.', price: 5000, type: 'frame', value: 'border-cyan-400 ring-4 ring-cyan-200 shadow-[0_0_15px_rgba(34,211,238,0.8)]', icon: 'StarIconFilled' },
];

interface ShopProps {
    state: AppState;
    availablePoints: number;
    onBack: () => void;
    onPurchase: (item: ShopItem) => void;
    onEquip: (item: ShopItem) => void;
    onAddCustomTheme?: (theme: CustomTheme, price: number) => void;
}

const formatPoints = (pts: number) => new Intl.NumberFormat('id-ID').format(pts);

// Helper to safely retrieve API Key
const getApiKey = (): string => {
    let key = '';
    try {
        if (typeof process !== 'undefined' && process.env && process.env.API_KEY) {
            key = process.env.API_KEY;
        }
    } catch (e) {}

    if (!key) {
        try {
            // @ts-ignore
            if (typeof import.meta !== 'undefined' && import.meta.env && import.meta.env.VITE_API_KEY) {
                // @ts-ignore
                key = import.meta.env.VITE_API_KEY;
            }
        } catch (e) {}
    }
    return key;
};

const Shop: React.FC<ShopProps> = ({ state, availablePoints, onBack, onPurchase, onEquip, onAddCustomTheme }) => {
    const [activeTab, setActiveTab] = useState<'all' | 'theme' | 'title' | 'frame' | 'lab'>('all');

    // Custom Theme Lab States
    const [themeConcept, setThemeConcept] = useState('');
    const [isGenerating, setIsGenerating] = useState(false);
    const [generatedTheme, setGeneratedTheme] = useState<CustomTheme | null>(null);
    const [genError, setGenError] = useState<string | null>(null);

    const filteredItems = SHOP_ITEMS.filter(item => activeTab === 'all' || item.type === activeTab);

    // Merge custom themes into the display list if in 'theme' tab or 'all'
    const customThemeItems: ShopItem[] = (state.customThemes || []).map(ct => ({
        id: ct.id,
        name: ct.name,
        description: 'Tema Kustom Buatanmu',
        price: 0, // Already bought
        type: 'theme',
        value: ct.id,
        icon: 'PaintBrushIcon'
    }));

    const itemsToDisplay = (activeTab === 'theme' || activeTab === 'all') 
        ? [...filteredItems, ...customThemeItems] 
        : filteredItems;

    const isOwned = (itemId: string) => state.inventory.includes(itemId) || itemId === 'theme_default' || itemId.startsWith('custom_');
    const isEquipped = (item: ShopItem) => {
        if (item.type === 'theme') return state.activeTheme === item.value;
        if (item.type === 'title') return state.userProfile.customTitle === item.value;
        if (item.type === 'frame') return state.userProfile.frameId === item.value;
        return false;
    };

    // --- AI THEME GENERATION LOGIC (Image + Palette) ---
    const handleGenerateTheme = async () => {
        if (!themeConcept.trim()) {
            setGenError('Tulis konsep tema dulu, dong!');
            return;
        }
        setIsGenerating(true);
        setGenError(null);
        setGeneratedTheme(null);

        try {
            const apiKey = getApiKey();
            const ai = new GoogleGenAI({ apiKey });

            // 1. Define Palette Prompt (Text Model)
            const palettePrompt = `Create a unique color palette for a UI theme based on this concept: "${themeConcept}".
            Return ONLY valid JSON (no markdown code blocks) with the following keys containing RGB color numbers (e.g., "255 255 255"):
            - primaryNavy: Main button/header color (RGB numbers, High contrast against lightBg)
            - primaryNavyDark: Darker shade for hover (RGB numbers)
            - accentTeal: Secondary/Highlight color (RGB numbers, Vibrant)
            - accentTealDark: Darker accent (RGB numbers)
            - lightBg: Semi-transparent background for cards (RGB numbers, e.g., "255 255 255" or "0 0 0" depending on if concept is dark/light)
            - darkText: Main text color (RGB numbers, Must be readable on lightBg)
            - secondaryGray: Subtitle text color (RGB numbers)
            Ensure the colors are harmonious with the concept.`;

            const paletteSchema = {
                type: Type.OBJECT,
                properties: {
                    primaryNavy: { type: Type.STRING },
                    primaryNavyDark: { type: Type.STRING },
                    accentTeal: { type: Type.STRING },
                    accentTealDark: { type: Type.STRING },
                    lightBg: { type: Type.STRING },
                    darkText: { type: Type.STRING },
                    secondaryGray: { type: Type.STRING },
                },
                required: ["primaryNavy", "primaryNavyDark", "accentTeal", "accentTealDark", "lightBg", "darkText", "secondaryGray"]
            };

            // 2. Define Image Prompt (Image Model)
            const imagePrompt = `A high-quality, aesthetic mobile wallpaper representing the concept: ${themeConcept}. Artistic, clean, suitable for app background. No text.`;

            // 3. Execute in Parallel
            const [paletteResponse, imageResponse] = await Promise.all([
                ai.models.generateContent({
                    model: 'gemini-2.5-flash',
                    contents: palettePrompt,
                    config: { responseMimeType: 'application/json', responseSchema: paletteSchema }
                }),
                ai.models.generateContent({
                    model: 'gemini-2.5-flash-image', // Using fast image model
                    contents: { parts: [{ text: imagePrompt }] }
                })
            ]);

            // 4. Parse Colors with robust error handling
            const textResponse = paletteResponse.text || "{}";
            // Strip markdown backticks if present (Model sometimes adds them despite strict schema)
            const cleanedText = textResponse.replace(/```json/g, '').replace(/```/g, '').trim();
            let colors;
            try {
                colors = JSON.parse(cleanedText);
            } catch (e) {
                console.error("JSON Parse Failed:", cleanedText);
                throw new Error("Gagal membaca resep warna dari AI. Coba lagi.");
            }

            // 5. Extract Image
            let base64Image = '';
            // Safe navigation for image parts
            const parts = imageResponse.candidates?.[0]?.content?.parts;
            if (parts) {
                for (const part of parts) {
                    if (part.inlineData) {
                        base64Image = part.inlineData.data;
                        break;
                    }
                }
            }

            if (!base64Image) {
                // Fallback to a gradient if image gen fails/refused
                console.warn("Image generation failed or empty, using fallback gradient.");
                // Throwing error for now as user requested real images, but could be handled gracefully.
                throw new Error("Gagal membuat gambar (Mungkin filter keamanan). Coba deskripsi yang lebih umum.");
            }

            const newTheme: CustomTheme = {
                id: `custom_${Date.now()}`,
                name: themeConcept.length > 20 ? themeConcept.substring(0, 20) + '...' : themeConcept,
                colors: {
                    '--color-primary-navy': colors.primaryNavy || '44 62 80',
                    '--color-primary-navy-dark': colors.primaryNavyDark || '31 43 56',
                    '--color-accent-teal': colors.accentTeal || '26 188 156',
                    '--color-accent-teal-dark': colors.accentTealDark || '22 160 133',
                    '--color-light-bg': colors.lightBg || '255 255 255',
                    '--color-dark-text': colors.darkText || '52 73 94',
                    '--color-secondary-gray': colors.secondaryGray || '127 140 141',
                    '--app-background': `url('data:image/png;base64,${base64Image}') no-repeat center center / cover fixed`
                }
            };

            setGeneratedTheme(newTheme);

        } catch (err: any) {
            console.error("Generation Error:", err);
            setGenError(err.message || 'Gagal meracik tema. Coba konsep lain ya!');
        } finally {
            setIsGenerating(false);
        }
    };

    const handleSaveCustomTheme = () => {
        if (generatedTheme && onAddCustomTheme) {
            onAddCustomTheme(generatedTheme, 5000); // Price 5000 for custom theme
            setGeneratedTheme(null);
            setThemeConcept('');
            setActiveTab('theme'); // Go to themes to see it
        }
    };

    return (
        <main className="p-4 pb-24 animate-fade-in max-w-3xl mx-auto">
            {/* HEADER */}
            <header className="mb-6 text-center sticky top-0 bg-light-bg z-10 py-2 transition-colors duration-300">
                <div className="flex justify-between items-center mb-4">
                    <button onClick={onBack} className="text-sm text-secondary-gray hover:text-primary-navy font-bold">
                        &larr; Kembali
                    </button>
                    <h1 className="text-2xl font-bold text-primary-navy flex items-center gap-2">
                        <ShoppingBagIcon className="w-6 h-6" /> Toko Mustika
                    </h1>
                    <div className="w-16"></div> {/* Spacer */}
                </div>

                {/* WALLET CARD */}
                <div className="bg-gradient-to-r from-indigo-600 to-purple-700 text-white rounded-xl p-4 shadow-lg flex justify-between items-center">
                    <div className="text-left">
                        <p className="text-indigo-100 text-xs font-medium uppercase tracking-wider">Saldo Anda</p>
                        <h2 className="text-3xl font-bold flex items-center gap-2">
                            <SparklesIcon className="w-6 h-6 text-yellow-300" />
                            {formatPoints(availablePoints)}
                        </h2>
                    </div>
                    <div className="text-right opacity-80">
                        <p className="text-xs">Kumpulkan XP dari</p>
                        <p className="text-xs">Misi & Lencana</p>
                    </div>
                </div>
            </header>

            {/* TABS */}
            <div className="flex justify-center gap-2 mb-6 overflow-x-auto no-scrollbar pb-2">
                {['all', 'theme', 'title', 'frame', 'lab'].map((tab) => (
                    <button
                        key={tab}
                        onClick={() => setActiveTab(tab as any)}
                        className={`px-4 py-2 rounded-full text-sm font-bold capitalize whitespace-nowrap transition-all ${
                            activeTab === tab 
                            ? 'bg-primary-navy text-white shadow-md' 
                            : 'bg-white text-secondary-gray border border-gray-200 hover:bg-gray-50'
                        }`}
                    >
                        {tab === 'all' ? 'Semua' : tab === 'theme' ? 'Tema' : tab === 'title' ? 'Gelar' : tab === 'frame' ? 'Bingkai' : '🧪 Lab AI'}
                    </button>
                ))}
            </div>

            {/* CUSTOM THEME LAB */}
            {activeTab === 'lab' ? (
                <section className="bg-white rounded-2xl shadow-lg p-6 border border-indigo-100">
                    <div className="text-center mb-6">
                        <div className="w-16 h-16 bg-gradient-to-br from-purple-500 to-pink-500 rounded-full flex items-center justify-center mx-auto mb-3 shadow-lg">
                            <PhotoIcon className="w-8 h-8 text-white" />
                        </div>
                        <h2 className="text-xl font-bold text-primary-navy">Desainer Tema AI</h2>
                        <p className="text-secondary-gray text-sm">AI akan membuatkan gambar wallpaper & warna tombol yang serasi!</p>
                    </div>

                    <div className="space-y-4">
                        <div>
                            <label className="block text-xs font-bold text-secondary-gray uppercase mb-1">Imajinasi Kamu</label>
                            <input 
                                type="text" 
                                value={themeConcept}
                                onChange={(e) => setThemeConcept(e.target.value)}
                                placeholder="Contoh: Kucing Cyberpunk di Luar Angkasa..."
                                className="w-full border-2 border-gray-200 rounded-xl px-4 py-3 focus:outline-none focus:border-accent-teal focus:ring-2 focus:ring-teal-100 transition-all"
                            />
                        </div>

                        {genError && <div className="p-3 bg-red-50 border border-red-200 rounded-lg text-red-600 text-sm text-center">{genError}</div>}

                        <button 
                            onClick={handleGenerateTheme}
                            disabled={isGenerating || !themeConcept.trim()}
                            className="w-full bg-primary-navy text-white font-bold py-3 rounded-xl hover:bg-primary-navy-dark transition-all flex items-center justify-center gap-2 disabled:bg-gray-300 disabled:cursor-not-allowed shadow-md hover:shadow-lg transform hover:-translate-y-0.5"
                        >
                            {isGenerating ? (
                                <><ArrowPathIcon className="w-5 h-5 animate-spin" /> Sedang Melukis...</>
                            ) : (
                                <><SparklesIcon className="w-5 h-5 text-yellow-300" /> Buat Tema Ajaib</>
                            )}
                        </button>
                    </div>

                    {/* PREVIEW SECTION */}
                    {generatedTheme && (
                        <div className="mt-8 animate-fade-in-up">
                            <div className="border-t border-gray-100 pt-6">
                                <h3 className="text-lg font-bold text-primary-navy mb-4 text-center">Hasil Racikan</h3>

