const sanitizeColorToRgb = (colorInput: string): string => {
    if (!colorInput) return '255 255 255'; // Default white

    // Check if it's already space separated numbers "255 255 255"
    if (/^\d{1,3}\s\d{1,3}\s\d{1,3}$/.test(colorInput.trim())) {
        return colorInput.trim();
    }

    // Check if Hex #RRGGBB
    if (colorInput.startsWith('#')) {
        const hex = colorInput.replace('#', '');
        const bigint = parseInt(hex, 16);
        const r = (bigint >> 16) & 255;
        const g = (bigint >> 8) & 255;
        const b = bigint & 255;
        return `${r} ${g} ${b}`;
    }

    // Fallback: return default if format unknown to prevent breakage
    console.warn("Unknown color format from AI, defaulting to white:", colorInput);
    return '255 255 255';
};

